30: func (s *Server) OFREPFlagEvaluation(ctx context.Context, r *ofrep.EvaluateFlagRequest) (*ofrep.EvaluationResponse, error) {
31: 	env, err := s.store.GetFromContext(ctx)
32: 	if err != nil {
33: 		return nil, err
34: 	}
35: 
36: 	store, err := env.EvaluationStore()
37: 	if err != nil {
38: 		return nil, err
39: 	}
40: 
41: 	if r.Key == "" {
42: 		return nil, newFlagMissingError()
43: 	}
44: 
45: 	var (
46: 		namespaceKey = getNamespace(ctx)
47: 		entityId     = getTargetingKey(r.Context)
48: 	)
49: 
50: 	flag, err := store.GetFlag(ctx, storage.NewResource(namespaceKey, r.Key))
51: 	if err != nil {
52: 		return nil, transformError(r.Key, err)
53: 	}
54: 
55: 	req := &rpcevaluation.EvaluationRequest{
56: 		EnvironmentKey: env.Key(),
57: 		NamespaceKey:   namespaceKey,
58: 		FlagKey:        r.Key,
59: 		EntityId:       entityId,
60: 		Context:        r.Context,
61: 	}
62: 
63: 	switch flag.Type {
64: 	case core.FlagType_VARIANT_FLAG_TYPE:
65: 		resp, err := s.variant(ctx, store, env, flag, req)
66: 		if err != nil {
67: 			return nil, transformError(r.Key, err)
68: 		}
69: 
70: 		if s.tracingEnabled {
71: 			s.addEvaluationEvent(ctx, env, namespaceKey, r.Key, entityId, "",
72: 				tracing.AttributeMatch.Bool(resp.Match),
73: 				tracing.AttributeVariant.String(resp.VariantKey),
74: 				tracing.AttributeReason.String(tracing.ReasonToValue(resp.Reason)),
75: 				tracing.AttributeSegments.StringSlice(resp.SegmentKeys),
76: 				tracing.AttributeFlagTypeVariant,
77: 			)
78: 		}
79: 
80: 		mm := map[string]any{}
81: 		if len(resp.SegmentKeys) > 0 {
82: 			mm[metaKeySegments] = strings.Join(resp.SegmentKeys, ",")
83: 		}
84: 		if resp.VariantAttachment != "" {
85: 			mm[metaKeyAttachment] = resp.VariantAttachment
86: 		}
87: 
88: 		value, err := structpb.NewValue(resp.VariantKey)
89: 		if err != nil {
90: 			return nil, err
91: 		}
92: 		metadata, err := structpb.NewStruct(mm)
93: 		if err != nil {
94: 			return nil, err
95: 		}
96: 		return &ofrep.EvaluationResponse{
97: 			Key:      resp.FlagKey,
98: 			Reason:   transformReason(resp.Reason),
99: 			Variant:  resp.VariantKey,
100: 			Value:    value,
101: 			Metadata: metadata,
102: 		}, nil
103: 
104: 	case core.FlagType_BOOLEAN_FLAG_TYPE:
105: 		resp, err := s.boolean(ctx, store, env, flag, req)
106: 		if err != nil {
107: 			return nil, transformError(r.Key, err)
108: 		}
109: 
110: 		if s.tracingEnabled {
111: 			s.addEvaluationEvent(ctx, env, namespaceKey, r.Key, entityId, "",
112: 				tracing.AttributeVariant.Bool(resp.Enabled),
113: 				tracing.AttributeReason.String(tracing.ReasonToValue(resp.Reason)),
114: 				tracing.AttributeSegments.StringSlice(resp.SegmentKeys),
115: 				tracing.AttributeFlagTypeBoolean,
116: 			)
117: 		}
118: 
119: 		value, err := structpb.NewValue(resp.Enabled)
120: 		if err != nil {
121: 			return nil, err
122: 		}
123: 
124: 		return &ofrep.EvaluationResponse{
125: 			Key:     resp.FlagKey,
126: 			Reason:  transformReason(resp.Reason),
127: 			Variant: strconv.FormatBool(resp.Enabled),
128: 			Value:   value,
129: 		}, nil
130: 	default:
131: 		return nil, errors.New("unsupported flag type for ofrep bridge")
132: 	}
133: }
