135: func (s *Server) OFREPFlagEvaluationBulk(ctx context.Context, r *ofrep.EvaluateBulkRequest) (*ofrep.BulkEvaluationResponse, error) {
136: 	env, err := s.store.GetFromContext(ctx)
137: 	if err != nil {
138: 		return nil, err
139: 	}
140: 
141: 	store, err := env.EvaluationStore()
142: 	if err != nil {
143: 		return nil, err
144: 	}
145: 
146: 	var (
147: 		namespaceKey = getNamespace(ctx)
148: 		flagKeys, ok = r.Context["flags"]
149: 		keys         = strings.Split(flagKeys, ",")
150: 	)
151: 
152: 	if !ok {
153: 		flags, err := store.ListFlags(ctx, storage.ListWithOptions(storage.NewNamespace(namespaceKey)))
154: 		if err != nil {
155: 			return nil, err
156: 		}
157: 
158: 		keys = make([]string, 0, len(flags.Results))
159: 		for _, flag := range flags.Results {
160: 			switch flag.Type {
161: 			case core.FlagType_BOOLEAN_FLAG_TYPE:
162: 				keys = append(keys, flag.Key)
163: 			case core.FlagType_VARIANT_FLAG_TYPE:
164: 				if flag.Enabled {
165: 					keys = append(keys, flag.Key)
166: 				}
167: 			}
168: 		}
169: 	}
170: 
171: 	responses := make([]*ofrep.EvaluationResponse, 0, len(keys))
172: 	for _, flagKey := range keys {
173: 		resp, err := s.OFREPFlagEvaluation(ctx, &ofrep.EvaluateFlagRequest{
174: 			Key:     flagKey,
175: 			Context: r.Context,
176: 		})
177: 		if err != nil {
178: 			return nil, err
179: 		}
180: 		responses = append(responses, resp)
181: 	}
182: 
183: 	return &ofrep.BulkEvaluationResponse{
184: 		Flags: responses,
185: 	}, nil
186: }
