190: func getTargetingKey(context map[string]string) string {
191: 	// https://openfeature.dev/docs/reference/concepts/evaluation-context/#targeting-key
192: 	if targetingKey, ok := context[ofrepCtxTargetingKey]; ok {
193: 		return targetingKey
194: 	}
195: 	return uuid.NewString()
