198: func getNamespace(ctx context.Context) string {
199: 	md, ok := metadata.FromIncomingContext(ctx)
200: 	if !ok {
201: 		return flipt.DefaultNamespace
202: 	}
203: 
204: 	namespace := md.Get(common.HeaderFliptNamespace)
205: 	if len(namespace) == 0 {
206: 		return flipt.DefaultNamespace
207: 	}
208: 
209: 	return namespace[0]
210: }
