212: func transformReason(reason rpcevaluation.EvaluationReason) ofrep.EvaluateReason {
213: 	switch reason {
214: 	case rpcevaluation.EvaluationReason_FLAG_DISABLED_EVALUATION_REASON:
215: 		return ofrep.EvaluateReason_DISABLED
216: 	case rpcevaluation.EvaluationReason_MATCH_EVALUATION_REASON:
217: 		return ofrep.EvaluateReason_TARGETING_MATCH
218: 	case rpcevaluation.EvaluationReason_DEFAULT_EVALUATION_REASON:
219: 		return ofrep.EvaluateReason_DEFAULT
220: 	default:
221: 		return ofrep.EvaluateReason_UNKNOWN
222: 	}
223: }
224: 
225: func transformError(key string, err error) error {
226: 	switch {
227: 	case flipterrors.AsMatch[flipterrors.ErrInvalid](err):
228: 		return newBadRequestError(key, err)
229: 	case flipterrors.AsMatch[flipterrors.ErrValidation](err):
230: 		return newBadRequestError(key, err)
231: 	case flipterrors.AsMatch[flipterrors.ErrNotFound](err):
232: 		return newFlagNotFoundError(key)
233: 	}
234: 	return err
235: }
236: 
237: const statusFlagKeyPointer = "ofrep-flag-key"
238: 
239: func statusWithKey(st *status.Status, key string) (*status.Status, error) {
240: 	return st.WithDetails(&structpb.Struct{
241: 		Fields: map[string]*structpb.Value{
242: 			statusFlagKeyPointer: structpb.NewStringValue(key),
243: 		},
244: 	})
245: }
246: 
247: func newBadRequestError(key string, err error) error {
248: 	v := status.New(codes.InvalidArgument, err.Error())
249: 	v, derr := statusWithKey(v, key)
250: 	if derr != nil {
251: 		return status.Errorf(codes.Internal, "failed to encode not bad request error")
252: 	}
253: 	return v.Err()
254: }
255: 
256: func newFlagNotFoundError(key string) error {
257: 	v := status.New(codes.NotFound, fmt.Sprintf("flag was not found %s", key))
258: 	v, derr := statusWithKey(v, key)
259: 	if derr != nil {
260: 		return status.Errorf(codes.Internal, "failed to encode not found error")
261: 	}
262: 	return v.Err()
263: }
264: 
265: func newFlagMissingError() error {
266: 	return status.Error(codes.InvalidArgument, "flag key was not provided")
267: }
