29: func ParseResourceType(typ string) (t ResourceType, err error) {
30: 	parts := strings.Split(strings.TrimPrefix(typ, "type.googleapis.com/"), ".")
31: 	if len(parts) == 0 {
32: 		return t, fmt.Errorf("unexpected package type %q", typ)
33: 	}
34: 
35: 	return ResourceType{
36: 		Package: strings.Join(parts[:len(parts)-1], "."),
37: 		Name:    parts[len(parts)-1],
38: 	}, nil
