101: type EnvironmentStore struct {
102: 	logger     *zap.Logger
103: 	byKey      map[string]Environment
104: 	defaultEnv Environment
105: 	mu         sync.RWMutex
106: }
107: 
108: func NewEnvironmentStore(logger *zap.Logger, envs ...Environment) (*EnvironmentStore, error) {
109: 	store := &EnvironmentStore{
110: 		logger: logger,
111: 		byKey:  map[string]Environment{},
112: 	}
113: 
114: 	for _, env := range envs {
115: 		store.byKey[env.Key()] = env
116: 		if env.Default() {
117: 			store.defaultEnv = env
118: 		}
119: 	}
120: 
121: 	if store.defaultEnv == nil {
122: 		env, ok := store.byKey[flipt.DefaultEnvironment]
123: 		switch {
124: 		case ok:
125: 			store.defaultEnv = env
126: 		case len(envs) == 1:
127: 			store.defaultEnv = envs[0]
128: 		default:
129: 			return nil, errors.New("explicit default environment required")
130: 		}
131: 	}
132: 
133: 	return store, nil
134: }
135: 
136: func (e *EnvironmentStore) List(ctx context.Context) iter.Seq[Environment] {
137: 	e.mu.RLock()
138: 	defer e.mu.RUnlock()
139: 
140: 	return iter.Seq[Environment](func(yield func(Environment) bool) {
141: 		for _, env := range e.byKey {
142: 			if !yield(env) {
143: 				return
144: 			}
145: 		}
146: 	})
147: }
148: 
149: func (e *EnvironmentStore) Add(env Environment) {
150: 	e.mu.Lock()
151: 	defer e.mu.Unlock()
152: 
153: 	e.byKey[env.Key()] = env
154: }
155: 
156: func (e *EnvironmentStore) Remove(key string) {
157: 	e.mu.Lock()
158: 	defer e.mu.Unlock()
159: 
160: 	delete(e.byKey, key)
161: }
162: 
163: func (e *EnvironmentStore) DeleteBranch(ctx context.Context, base, branch string) error {
164: 	baseEnv, err := e.Get(ctx, base)
165: 	if err != nil {
166: 		return err
167: 	}
168: 
169: 	if err := baseEnv.DeleteBranch(ctx, branch); err != nil {
170: 		return err
171: 	}
172: 
173: 	e.mu.Lock()
174: 	delete(e.byKey, branch)
175: 	e.mu.Unlock()
176: 
177: 	return nil
178: }
179: 
180: func (e *EnvironmentStore) Branch(ctx context.Context, base string, branch string) (Environment, error) {
181: 	baseEnv, err := e.Get(ctx, base)
182: 	if err != nil {
183: 		return nil, err
184: 	}
185: 
186: 	for key := range e.byKey {
187: 		if strings.EqualFold(key, strings.TrimSpace(branch)) {
188: 			return nil, errors.ErrAlreadyExistsf("environment: %q", branch)
189: 		}
190: 	}
191: 
192: 	branchEnv, err := baseEnv.Branch(ctx, branch)
193: 	if err != nil {
194: 		return nil, err
195: 	}
196: 
197: 	e.Add(branchEnv)
198: 
199: 	return branchEnv, nil
200: }
201: 
202: func (e *EnvironmentStore) Propose(ctx context.Context, base string, branch string, opts ProposalOptions) (*environments.EnvironmentProposalDetails, error) {
203: 	baseEnv, err := e.Get(ctx, base)
204: 	if err != nil {
205: 		return nil, err
206: 	}
207: 
208: 	branchEnv, err := e.Get(ctx, branch)
209: 	if err != nil {
210: 		return nil, err
211: 	}
212: 
213: 	return baseEnv.Propose(ctx, branchEnv, opts)
214: }
