216: // Get returns the environment identified by key.
217: func (e *EnvironmentStore) Get(ctx context.Context, key string) (Environment, error) {
218: 	e.mu.RLock()
219: 	defer e.mu.RUnlock()
220: 
221: 	env, ok := e.byKey[key]
222: 	if !ok {
223: 		return nil, errors.ErrNotFoundf("environment: %q", key)
224: 	}
225: 
226: 	return env, nil
227: }
228: 
229: // GetFromContext returns the environment identified by name from the context or the default environment if no name is provided.
230: func (e *EnvironmentStore) GetFromContext(ctx context.Context) (Environment, error) {
231: 	env, ok := common.FliptEnvironmentFromContext(ctx)
232: 	if ok {
233: 		ee, err := e.Get(ctx, env)
234: 		if err != nil {
235: 			// If the requested environment is "default" and it doesn't exist,
236: 			// fall back to the default environment instead of returning an error.
237: 			// This ensures compatibility with SDKs that explicitly set environment="default"
238: 			// when the actual default environment has a different key.
239: 			if env == flipt.DefaultEnvironment {
240: 				return e.defaultEnv, nil
241: 			}
242: 			return nil, fmt.Errorf("failed to get environment %q from context: %w", env, err)
243: 		}
244: 		return ee, nil
245: 	}
246: 
247: 	return e.defaultEnv, nil
248: }
