35: // ListEnvironments returns a list of all environments.
36: func (s *Server) ListEnvironments(ctx context.Context, req *environments.ListEnvironmentsRequest) (el *environments.ListEnvironmentsResponse, err error) {
37: 	el = &environments.ListEnvironmentsResponse{}
38: 
39: 	// First collect all environments
40: 	for env := range s.envs.List(ctx) {
41: 		cfg := env.Configuration()
42: 
43: 		el.Environments = append(el.Environments, &environments.Environment{
44: 			Key:           env.Key(),
45: 			Name:          env.Key(),
46: 			Default:       new(env.Default()),
47: 			Configuration: cfg,
48: 		})
49: 	}
50: 
51: 	// Only filter if we have viewable environments in context
52: 	viewableEnvironments, ok := ctx.Value(authz.EnvironmentsKey).([]string)
53: 	if ok {
54: 		// if user has access to all environments, return all environments
55: 		if len(viewableEnvironments) == 1 && viewableEnvironments[0] == "*" {
56: 			return el, nil
57: 		}
58: 
